import log, { LogLevelDesc } from 'loglevel';

export function setLogLevel() {
  if (process.env.E2E_TOKEN_FETCHER_LOGLEVEL) {
    log.setLevel(process.env.E2E_TOKEN_FETCHER_LOGLEVEL as LogLevelDesc);
  } else {
    log.setLevel('info');
  }
}

export function logVariables() {
  setLogLevel();

  log.debug('=== e2e-token-fetcher PROXY environment variables ===');
  log.debug(`no_proxy         = ${process.env.no_proxy}`);
  log.debug(`NO_PROXY         = ${process.env.NO_PROXY}`);
  log.debug(`https_proxy      = ${process.env.https_proxy}`);
  log.debug(`HTTPS_PROXY      = ${process.env.HTTPS_PROXY}`);
  log.debug(`http_proxy       = ${process.env.http_proxy}`);
  log.debug(`HTTP_PROXY       = ${process.env.HTTP_PROXY}`);
  log.debug('----- Variables not used ----------------------------');
  log.debug(`HTTPS_PROXY_URL  = ${process.env.HTTPS_PROXY_URL}`);
  log.debug(`HTTPS_PROXY_HOST = ${process.env.HTTPS_PROXY_HOST}`);
  log.debug(`HTTPS_PROXY_PORT = ${process.env.HTTPS_PROXY_PORT}`);
  log.debug(`HTTP_PROXY_URL   = ${process.env.HTTP_PROXY_URL}`);
  log.debug(`HTTP_PROXY_HOST  = ${process.env.HTTP_PROXY_HOST}`);
  log.debug(`HTTP_PROXY_PORT  = ${process.env.HTTP_PROXY_PORT}`);
  log.debug('=====================================================');

  if (process.env.E2E_TOKEN_FETCHER_NOACS) {
    log.debug('* Using experimental mode without axios-cookiejar-support');
  } else {
    log.debug('* Using legacy mode with axios-cookiejar-support v1.x');
  }
}
